import string
import random
from http.server import BaseHTTPRequestHandler, HTTPServer
from urllib.parse import urlparse, parse_qs
import threading

# URL Storage
class URLStore:
    def __init__(self):
        self.url_map = {}
        self.short_to_long = {}

    def shorten_url(self, long_url):
        if long_url in self.url_map:
            return self.url_map[long_url]

        short_url = self._generate_short_url()
        self.url_map[long_url] = short_url
        self.short_to_long[short_url] = long_url
        return short_url

    def get_long_url(self, short_url):
        return self.short_to_long.get(short_url)

    def _generate_short_url(self, length=6):
        chars = string.ascii_letters + string.digits
        while True:
            short_url = ''.join(random.choice(chars) for _ in range(length))
            if short_url not in self.short_to_long:
                break
        return short_url


# HTTP Server for URL Shortener
class URLShortenerHTTPRequestHandler(BaseHTTPRequestHandler):
    url_store = URLStore()

    def do_GET(self):
        parsed_path = urlparse(self.path)
        path = parsed_path.path.strip('/')

        if path == 'shorten':
            query_params = parse_qs(parsed_path.query)
            long_url = query_params.get('url')
            if long_url:
                short_url = self.url_store.shorten_url(long_url[0])
                self._send_response(200, f'Shortened URL: http://localhost:8080/{short_url}\n')
            else:
                self._send_response(400, 'URL parameter is missing.\n')
        else:
            long_url = self.url_store.get_long_url(path)
            if long_url:
                self.send_response(302)
                self.send_header('Location', long_url)
                self.end_headers()
            else:
                self._send_response(404, 'Short URL not found.\n')

    def _send_response(self, code, message):
        self.send_response(code)
        self.send_header('Content-type', 'text/plain')
        self.end_headers()
        self.wfile.write(message.encode('utf-8'))


# Start the HTTP server
def run(server_class=HTTPServer, handler_class=URLShortenerHTTPRequestHandler, port=8080):
    server_address = ('', port)
    httpd = server_class(server_address, handler_class)
    print(f'Starting URL shortener server on port {port}...')
    httpd.serve_forever()

# To allow graceful shutdown on Ctrl+C
def start_server():
    server_thread = threading.Thread(target=run)
    server_thread.daemon = True
    server_thread.start()
    try:
        while True:
            pass
    except KeyboardInterrupt:
        print("\nServer is shutting down...")

if __name__ == '__main__':
    start_server()
