import string
import random
from http.server import BaseHTTPRequestHandler, HTTPServer
from urllib.parse import urlparse, parse_qs

# In-memory storage for URL mappings
url_mapping = {}
base_url = "http://localhost:8080/"

# URL shortening logic
def generate_short_url():
    characters = string.ascii_letters + string.digits
    return ''.join(random.choice(characters) for _ in range(6))

def shorten_url(original_url):
    short_url = generate_short_url()
    while short_url in url_mapping:
        short_url = generate_short_url()
    url_mapping[short_url] = original_url
    return short_url

# HTTP server to handle URL shortening and redirects
class URLShortenerHTTPRequestHandler(BaseHTTPRequestHandler):
    def do_GET(self):
        parsed_path = urlparse(self.path)
        path_components = parsed_path.path.strip('/').split('/')

        if len(path_components) == 1 and path_components[0]:
            short_url = path_components[0]
            if short_url in url_mapping:
                self.send_response(301)
                self.send_header('Location', url_mapping[short_url])
                self.end_headers()
            else:
                self.send_error(404, 'Short URL not found')
        elif parsed_path.path == '/shorten':
            query_params = parse_qs(parsed_path.query)
            original_url = query_params.get('url')
            if original_url:
                short_url = shorten_url(original_url[0])
                self.send_response(200)
                self.send_header('Content-type', 'text/plain')
                self.end_headers()
                self.wfile.write(f"{base_url}{short_url}".encode())
            else:
                self.send_error(400, 'URL parameter is missing')
        else:
            self.send_error(404, 'Endpoint not found')

def run(server_class=HTTPServer, handler_class=URLShortenerHTTPRequestHandler, port=8080):
    server_address = ('', port)
    httpd = server_class(server_address, handler_class)
    print(f'Starting URL shortener server on port {port}')
    httpd.serve_forever()

if __name__ == '__main__':
