"""
A simple URL shortener using Flask with in-memory storage.
"""

import string
import random
from flask import Flask, request, redirect, jsonify, abort

app = Flask(__name__)

# In-memory storage mapping shortened codes to original URLs
url_store = {}
# A reverse lookup, mapping original URL to its code (to avoid duplications)
reverse_lookup = {}

# Characters to use for short codes (base62: 0-9, a-z, A-Z)
ALPHABET = string.digits + string.ascii_lowercase + string.ascii_uppercase
CODE_LENGTH = 6  # length of the generated short code

def generate_short_code():
    """Generate a random short code."""
    return ''.join(random.choices(ALPHABET, k=CODE_LENGTH))

def get_or_create_short_url(original_url):
    """Return the short code for a given URL, creating one if needed."""
    # If we've already shortened this URL, return the existing code.
    if original_url in reverse_lookup:
        return reverse_lookup[original_url]

    # Otherwise, create a new unique short code.
    short_code = generate_short_code()
    # Ensure uniqueness: regenerate if collision (very unlikely)
    while short_code in url_store:
        short_code = generate_short_code()

    url_store[short_code] = original_url
    reverse_lookup[original_url] = short_code

    return short_code

@app.route('/shorten', methods=['POST'])
def shorten_url():
    """
    Expects JSON body:
    {
        "url": "<original_url>"
    }
    Returns JSON response:
    {
        "short_url": "<domain>/<short_code>"
    }
    """
    data = request.get_json()
    if not data or "url" not in data:
        return jsonify({"error": "Request body must contain 'url' field."}), 400

    original_url = data["url"]
    short_code = get_or_create_short_url(original_url)

    # Build full short URL response based on request host and scheme.
    short_url = f"{request.scheme}://{request.host}/{short_code}"
    return jsonify({"short_url": short_url}), 201

@app.route('/<string:short_code>')
def redirect_short_url(short_code):
    """
    Redirects a short URL to the original URL.
    """
    original_url = url_store.get(short_code)
    if original_url:
        return redirect(original_url, code=302)
    else:
        abort(404, description="Short URL not found.")

if __name__ == '__main__':
    # Run the Flask HTTP server on port 5000 by default.
    app.run(host='0.0.0.0', port=5000, debug=True)

