#!/usr/bin/env python3
import string
from flask import Flask, request, redirect, jsonify, abort

app = Flask(__name__)

# In-memory storage for shortened URLs
url_storage = {}
# Global counter for generating unique short codes
counter = 1

# Base62 alphabet for encoding numbers
ALPHABET = string.ascii_letters + string.digits
BASE = len(ALPHABET)

def encode(num):
    """Encode an integer into a base62 string."""
    if num == 0:
        return ALPHABET[0]
    parts = []
    while num:
        num, rem = divmod(num, BASE)
        parts.append(ALPHABET[rem])
    return ''.join(reversed(parts))

@app.route('/shorten', methods=['POST'])
def shorten_url():
    """
    Shorten a URL.
    Expects JSON payload: {"url": "http://example.com"}
    Returns shortened URL in JSON format.
    """
    global counter

    data = request.get_json()
    if not data or 'url' not in data:
        return jsonify({"error": "Missing 'url' in request data"}), 400

    original_url = data['url']
    # Generate a short code using the current counter value
    short_code = encode(counter)
    url_storage[short_code] = original_url
    counter += 1

    # Build the full shortened URL using the request's URL root
    short_url = request.url_root.rstrip('/') + '/' + short_code
    return jsonify({"short_url": short_url}), 201

@app.route('/<code>', methods=['GET'])
def redirect_short_url(code):
    """
    Redirect to the original URL based on the short code.
    """
    original_url = url_storage.get(code)
    if original_url:
        return redirect(original_url, code=302)
    else:
        abort(404)

if __name__ == '__main__':
    # Run the server on port 5000 by default
    app.run(debug=True)

