import hashlib
import string
import random
import json
import os
from datetime import datetime
from urllib.parse import urlparse
from http.server import HTTPServer, BaseHTTPRequestHandler
from urllib.parse import parse_qs, urlparse
import threading
import time

class URLStorage:
    def __init__(self, storage_file='urls.json'):
        self.storage_file = storage_file
        self.urls = self._load_urls()
        self.reverse_lookup = {v['original_url']: k for k, v in self.urls.items()}

    def _load_urls(self):
        if os.path.exists(self.storage_file):
            try:
                with open(self.storage_file, 'r') as f:
                    return json.load(f)
            except (json.JSONDecodeError, IOError):
                return {}
        return {}

    def _save_urls(self):
        try:
            with open(self.storage_file, 'w') as f:
                json.dump(self.urls, f, indent=2)
        except IOError:
            print(f"Error saving to {self.storage_file}")

    def store_url(self, short_code, original_url):
        self.urls[short_code] = {
            'original_url': original_url,
            'created_at': datetime.now().isoformat(),
            'access_count': 0
        }
        self.reverse_lookup[original_url] = short_code
        self._save_urls()

    def get_url(self, short_code):
        if short_code in self.urls:
            self.urls[short_code]['access_count'] += 1
            self._save_urls()
            return self.urls[short_code]['original_url']
        return None

    def url_exists(self, original_url):
        return original_url in self.reverse_lookup

    def get_short_code(self, original_url):
        return self.reverse_lookup.get(original_url)

class URLShortener:
    def __init__(self, base_url='http://localhost:8080', storage=None):
        self.base_url = base_url.rstrip('/')
        self.storage = storage or URLStorage()
        self.characters = string.ascii_letters + string.digits

    def _generate_short_code(self, length=6):
        return ''.join(random.choices(self.characters, k=length))

    def _is_valid_url(self, url):
        try:
            result = urlparse(url)
            return all([result.scheme, result.netloc])
        except:
            return False

    def shorten_url(self, original_url):
        if not self._is_valid_url(original_url):
            raise ValueError("Invalid URL provided")

        # Check if URL already exists
        if self.storage.url_exists(original_url):
            short_code = self.storage.get_short_code(original_url)
            return f"{self.base_url}/{short_code}"

        # Generate unique short code
        max_attempts = 10
        for _ in range(max_attempts):
            short_code = self._generate_short_code()
            if self.storage.get_url(short_code) is None:
                self.storage.store_url(short_code, original_url)
                return f"{self.base_url}/{short_code}"

        raise RuntimeError("Unable to generate unique short code")

    def expand_url(self, short_code):
        return self.storage.get_url(short_code)

class URLShortenerHandler(BaseHTTPRequestHandler):
    def __init__(self, shortener, *args, **kwargs):
        self.shortener = shortener
        super().__init__(*args, **kwargs)

    def do_GET(self):
        parsed_path = urlparse(self.path)
        path = parsed_path.path.strip('/')

        if not path:
            self._serve_home_page()
        elif path == 'shorten':
            self._serve_shorten_form()
        else:
            # Try to redirect
            original_url = self.shortener.expand_url(path)
            if original_url:
                self._redirect(original_url)
            else:
                self._send_404()

    def do_POST(self):
        if self.path == '/shorten':
            self._handle_shorten_request()
        else:
            self._send_404()

    def _serve_home_page(self):
        html = """
        <!DOCTYPE html>
        <html>
        <head>
            <title>URL Shortener</title>
            <style>
                body { font-family: Arial, sans-serif; max-width: 600px; margin: 50px auto; padding: 20px; }
                .form-group { margin: 20px 0; }
                input[type="url"] { width: 100%; padding: 10px; font-size: 16px; }
                button { padding: 10px 20px; font-size: 16px; background: #007bff; color: white; border: none; cursor: pointer; }
                button:hover { background: #0056b3; }
                .result { margin: 20px 0; padding: 15px; background: #f8f9fa; border-radius: 5px; }
            </style>
        </head>
        <body>
            <h1>URL Shortener</h1>
            <form method="post" action="/shorten">
                <div class="form-group">
                    <label for="url">Enter URL to shorten:</label>
                    <input type="url" id="url" name="url" placeholder="https://example.com" required>
                </div>
                <button type="submit">Shorten URL</button>
            </form>
        </body>
        </html>
        """
