                raise ValueError("Custom code already exists")
            short_code = custom_code
        else:
            # Try deterministic approach first
            short_code = self._create_deterministic_code(original_url)

            # If collision, generate random code
            if self.storage.code_exists(short_code):
                attempts = 0
                while attempts < 10:
                    short_code = self._generate_short_code()
                    if not self.storage.code_exists(short_code):
                        break
                    attempts += 1
                else:
                    raise RuntimeError("Unable to generate unique short code")

        self.storage.store_url(short_code, original_url)
        return short_code

